      // Inicialización de la página
      document.addEventListener("DOMContentLoaded", function () {
        // No necesitamos inicializar AOS ya que estamos usando animaciones nativas de CSS

        // Header scroll effect
        const header = document.getElementById("main-header");
        if (header) {
          window.addEventListener("scroll", function () {
            if (window.scrollY > 50) {
              header.classList.add("py-2");
              header.classList.add("shadow-xl");
              header.classList.add("bg-white");
              header.classList.add("bg-opacity-95");
            } else {
              header.classList.remove("py-2");
              header.classList.remove("shadow-xl");
              header.classList.remove("bg-white");
              header.classList.remove("bg-opacity-95");
            }
          });
        }

        // Mobile menu toggle with animation
        const mobileMenuButton = document.getElementById("mobile-menu-button");
        const mobileMenu = document.getElementById("mobile-menu");

        if (mobileMenuButton && mobileMenu) {
          mobileMenuButton.addEventListener("click", function () {
            mobileMenu.classList.toggle("hidden");

            // Animation
            if (!mobileMenu.classList.contains("hidden")) {
              setTimeout(function () {
                mobileMenu.classList.remove("-translate-y-2", "opacity-0");
                mobileMenu.classList.add("translate-y-0", "opacity-100");
              }, 10);
            } else {
              mobileMenu.classList.add("-translate-y-2", "opacity-0");
              mobileMenu.classList.remove("translate-y-0", "opacity-100");
            }
          });
        }

        // Cursor follower effect (versión simple sin GSAP)
        const cursorFollower = document.getElementById("cursor-follower");
        if (cursorFollower) {
          document.addEventListener("mousemove", function (e) {
            // Usar setAttribute para evitar problemas de TypeScript
            try {
              cursorFollower.setAttribute(
                "style",
                `transform: translate(${e.clientX - 128}px, ${e.clientY - 128}px); transition: transform 0.3s ease-out;`,
              );
            } catch (error) {
              console.error("Error al mover el cursor follower:", error);
            }
          });
        }
      });
    </script> <script src="/js/trial-popup.js"></script></body> </html> 